import argparse
from kafka.admin import AdminClient, NewTopic, ConfigResource

def create_topic(admin_client, topic_name):
    new_topic = NewTopic(topic_name, 3, 1)
    try:
        admin_client.create_topics(new_topics=[new_topic])
    except Exception as e:
        print(f"Error creating topic {topic_name}: {e}")

def manage_partitions(admin_client, topic_name, num_partitions=None, replication_factor=None):
    if num_partitions is not None and replication_factor is not None:
        try:
            admin_client.alter_configs({
                ConfigResource('topic', topic_name): {
                    'num.partitions': num_partitions,
                    'replication.factor': replication_factor
                }
            })
        except Exception as e:
            print(f"Error managing partitions for topic {topic_name}: {e}")

def configure_topic_settings(admin_client, topic_name, config=None):
    if config is not None:
        try:
            admin_client.alter_configs({
                ConfigResource('topic', topic_name): config
            })
        except Exception as e:
            print(f"Error configuring topic settings for {topic_name}: {e}")

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-server', required=True, help='Bootstrap server URL')
    parser.add_argument('--create-topic', action='store_true', help='Create a new topic')
    parser.add_argument('--manage-partitions', action='store_true', help='Manage partitions for an existing topic')
    parser.add_argument('--configure-settings', action='store_true', help='Configure topic settings')
    parser.add_argument('--topic-name', required=True, help='Topic name')
    parser.add_argument('--num-partitions', type=int, help='Number of partitions (for manage_partitions)')
    parser.add_argument('--replication-factor', type=int, help='Replication factor (for manage_partitions)')
    parser.add_argument('--config', nargs='+', help='Configuration settings (for configure_settings)')

    args = parser.parse_args()

    admin_client = AdminClient({
        'bootstrap_servers': [args.bootstrap_server]
    })

    if args.create_topic:
        create_topic(admin_client, args.topic_name)

    if args.manage_partitions:
        manage_partitions(admin_client, args.topic_name, num_partitions=args.num_partitions, replication_factor=args.replication_factor)

    if args.configure_settings:
        config = {}
        for key_value in args.config:
            key, value = key_value.split('=')
            config[key] = value
        configure_topic_settings(admin_client, args.topic_name, config=config)

if __name__ == '__main__':
    main()